module RefModule (
    input clk,
    input reset,
    input up,
    output [2:0] count );reg [2:0] count_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            count_reg <= 3'b000;
        else if (up)
            count_reg <= count_reg + 1;
        else
            count_reg <= count_reg - 1;
    end

    assign count = count_reg;

endmodule
